double arrav(int p[], int len) {
  double av = 0;  int i;
  for(i = 0; i < len; i++) {
    av += (double)p[i];
  }
  return av / len;
}
double arrp(int *p, int len) {
  double av = 0;  int i;
  for (i = 0; i < len; i++) {
    av += (double)(*(p + i));
  }
  return av / len;
}
